ksm_full_scans_fd, buf, sizeof(buf) - 1, 0);\n\tclose(ksm_full_scans_fd);\n\tif (ret <= 0)\n\t\treturn -errno;\n\tbuf[ret] = 0;\n\n\treturn strtol(buf, NULL, 10);\n}\n\nint ksm_use_zero_pages(void)\n{\n\tint ksm_use_zero_pages_fd;\n\tssize_t ret;\n\n\tksm_use_zero_pages_fd = open(\"/sys/kernel/mm/ksm/use_zero_pages\", O_RDWR);\n\tif (ksm_use_zero_pages_fd < 0)\n\t\treturn -errno;\n\n\tret = write(ksm_use_zero_pages_fd, \"1\", 1);\n\tclose(ksm_use_zero_pages_fd);\n\treturn ret == 1 ? 0 : -errno;\n}\n\nint ksm_start(void)\n{\n\tint ksm_fd;\n\tssize_t ret;\n\tlong start_scans, end_scans;\n\n\tksm_fd = open(\"/sys/kernel/mm/ksm/run\", O_RDWR);\n\tif (ksm_fd < 0)\n\t\treturn -errno;\n\n\t/* Wait for two full scans such that any possible merging happened. */\n\tstart_scans = ksm_get_full_scans();\n\tif (start_scans < 0) {\n\t\tclose(ksm_fd);\n\t\treturn start_scans;\n\t}\n\tret = write(ksm_fd, \"1\", 1);\n\tclose(ksm_fd);\n\tif (ret != 1)\n\t\treturn -errno;\n\tdo {\n\t\tend_scans = ksm_get_full_scans();\n\t\tif (end_scans < 0)\n\t\t\treturn end_scans;\n\t} while (end_scans < start_scans + 2);\n\n\treturn 0;\n}\n\nint ksm_stop(void)\n{\n\tint ksm_fd;\n\tssize_t ret;\n\n\tksm_fd = open(\"/sys/kernel/mm/ksm/run\", O_RDWR);\n\tif (ksm_fd < 0)\n\t\treturn -errno;\n\n\tret = write(ksm_fd, \"2\", 1);\n\tclose(ksm_fd);\n\treturn ret == 1 ? 0 : -errno;\n}\n\nint get_hardware_corrupted_size(unsigned long *val)\n{\n\tunsigned long size;\n\tchar *line = NULL;\n\tsize_t linelen = 0;\n\tFILE *f = fopen(\"/proc/meminfo\", \"r\");\n\tint ret = -1;\n\n\tif (!f)\n\t\treturn ret;\n\n\twhile (getline(&line, &linelen, f) > 0) {\n\t\tif (sscanf(line, \"HardwareCorrupted: %12lu kB\", &size) == 1) {\n\t\t\t*val = size;\n\t\t\tret = 0;\n\t\t\tbreak;\n\t\t}\n\t}\n\n\tfree(line);\n\tfclose(f);\n\treturn ret;\n}\n\nint unpoison_memory(unsigned long pfn)\n{\n\tint unpoison_fd, len;\n\tchar buf[32];\n\tssize_t ret;\n\n\tunpoison_fd = open(\"/sys/kernel/debug/hwpoison/unpoison-pfn\", O_WRONLY);\n\tif (unpoison_fd < 0)\n\t\treturn -errno;\n\n\tlen = sprintf(buf, \"0x%lx\\n\", pfn);\n\tret = write(unpoison_fd, buf, len);\n\tclose(unpoison_fd);\n\n\treturn ret > 0 ? 0 : -errno;\n}\n"}",
